import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import DataLoader, Dataset
from torchvision import transforms
from torchvision.models import resnet18, ResNet18_Weights
from tqdm import tqdm
import requests
from io import BytesIO
from PIL import Image

# --- Configuration ---
PRETRAINED_MODEL_URL = "https://download.pytorch.org/models/resnet18-f37072fd.pth" # Example URL for a ResNet18 checkpoint
NUM_CLASSES = 2  # Example: binary classification
BATCH_SIZE = 32
LEARNING_RATE = 0.001
NUM_EPOCHS = 5
DEVICE = torch.device("cuda" if torch.cuda.is_available() else "cpu")

# --- 1. Custom Dataset (Example: Replace with your actual dataset) ---
class CustomDataset(Dataset):
    def __init__(self, num_samples=100, transform=None):
        self.num_samples = num_samples
        self.transform = transform
        # In a real scenario, you would load your images and labels here.
        # For demonstration, we'll create dummy data.
        self.dummy_images = [Image.new('RGB', (224, 224), color = (i*2, i*3, i*4)) for i in range(num_samples)]
        self.dummy_labels = [i % NUM_CLASSES for i in range(num_samples)]

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.dummy_images[idx]
        label = self.dummy_labels[idx]

        if self.transform:
            image = self.transform(image)

        return image, label

# --- 2. Download and Load Pretrained Model ---
def download_and_load_model(model_url, device):
    print(f"Downloading model from: {model_url}")
    response = requests.get(model_url, stream=True)
    response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)

    # Wrap the content in BytesIO for torch.load to read
    # This avoids saving to disk if not strictly necessary
    model_data = BytesIO(response.content)

    print("Loading model state dict...")
    # Map to CPU first, then move to device later if needed for consistency
    state_dict = torch.load(model_data, map_location='cpu')
    print("Model state dict loaded successfully.")
    return state_dict

# --- 3. Main Script ---
if __name__ == "__main__":
    # 3.1. Define Transformations
    data_transforms = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    # 3.2. Load Data
    print("Initializing custom dataset and dataloaders...")
    train_dataset = CustomDataset(num_samples=100, transform=data_transforms)
    train_loader = DataLoader(train_dataset, batch_size=BATCH_SIZE, shuffle=True)
    print(f"Dataset has {len(train_dataset)} samples.")

    # 3.3. Initialize Pretrained Model
    # It's good practice to initialize the model with default weights first
    # and then load the custom state_dict to ensure architecture compatibility.
    model = resnet18(weights=ResNet18_Weights.IMAGENET1K_V1)

    # Download and load the custom state_dict from URL
    try:
        pretrained_state_dict = download_and_load_model(PRETRAINED_MODEL_URL, DEVICE)
        # Load the downloaded state_dict into the model
        # strict=True means that the keys in state_dict must exactly match the keys in model's state_dict
        model.load_state_dict(pretrained_state_dict, strict=True)
        print("Pretrained model loaded successfully from URL.")
    except Exception as e:
        print(f"Error downloading or loading pretrained model: {e}")
        print("Falling back to default ImageNet weights for ResNet18.")
        # If download fails, use torchvision's default pretrained weights
        model = resnet18(weights=ResNet18_Weights.IMAGENET1K_V1)


    # 3.4. Modify the Classifier Head for Transfer Learning
    # Freeze all layers except the final classification layer
    for param in model.parameters():
        param.requires_grad = False

    # Replace the final fully connected layer
    num_ftrs = model.fc.in_features
    model.fc = nn.Linear(num_ftrs, NUM_CLASSES)
    model = model.to(DEVICE)
    print(f"Model moved to {DEVICE}.")
    print(f"Model architecture modified for {NUM_CLASSES} classes.")

    # 3.5. Define Loss Function and Optimizer
    criterion = nn.CrossEntropyLoss()
    # Only optimize parameters that are unfrozen (i.e., the new fc layer)
    optimizer = optim.Adam(model.fc.parameters(), lr=LEARNING_RATE)

    # 3.6. Fine-tuning Loop
    print("\nStarting fine-tuning...")
    for epoch in range(NUM_EPOCHS):
        model.train()  # Set model to training mode
        running_loss = 0.0
        correct_predictions = 0
        total_samples = 0

        # Use tqdm for a progress bar
        progress_bar = tqdm(train_loader, desc=f"Epoch {epoch+1}/{NUM_EPOCHS}", leave=False)
        for inputs, labels in progress_bar:
            inputs, labels = inputs.to(DEVICE), labels.to(DEVICE)

            optimizer.zero_grad()  # Zero the parameter gradients

            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()  # Backpropagate
            optimizer.step()  # Update weights

            running_loss += loss.item() * inputs.size(0)
            _, predicted = torch.max(outputs.data, 1)
            total_samples += labels.size(0)
            correct_predictions += (predicted == labels).sum().item()

            progress_bar.set_postfix(loss=loss.item())

        epoch_loss = running_loss / len(train_dataset)
        epoch_accuracy = correct_predictions / total_samples * 100
        print(f"Epoch {epoch+1}/{NUM_EPOCHS} - Loss: {epoch_loss:.4f}, Accuracy: {epoch_accuracy:.2f}%")

    print("\nFine-tuning complete!")

    # 3.7. Save the fine-tuned model (optional)
    # torch.save(model.state_dict(), "fine_tuned_model.pth")
    # print("Fine-tuned model saved as fine_tuned_model.pth")

    # Example: Make a prediction with the fine-tuned model (optional)
    model.eval()
    with torch.no_grad():
        sample_input, _ = train_dataset[0]
        sample_input = sample_input.unsqueeze(0).to(DEVICE) # Add batch dimension
        output = model(sample_input)
        predicted_class = torch.argmax(output).item()
        print(f"\nExample prediction for first sample: Class {predicted_class}")